"use client";

import type { ColumnDef } from "@tanstack/react-table";
import { redirect } from "next/navigation";
import { useSession } from "next-auth/react";
import { useEffect, useState } from "react";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { DataTable } from "@/components/ui/data-table/data-table";
import { DataTableDialog } from "@/components/ui/data-table/data-table-dialog";
import { routes } from "@/config/routes";
import { env } from "@/env";
import { useTeamId } from "@/hooks/use-team-id";
import { useToast } from "@/hooks/use-toast";
import { LocalProjectStorage } from "@/lib/local-storage/project-storage";
import { LocalTeamStorage } from "@/lib/local-storage/team-storage";
import { createProject, deleteProject, updateProject } from "@/server/actions/projects";

// Helper to fetch team projects via API
async function fetchTeamProjects(teamId: string): Promise<any[]> {
  const response = await fetch(`${routes.api.projects}?teamId=${encodeURIComponent(teamId)}`);
  if (!response.ok) {
    return [];
  }
  const data = await response.json();
  return data.projects ?? [];
}

interface Project {
  id: string;
  name: string;
  teamId: string;
  team: {
    id: string;
    name: string;
  };
  members: {
    id: string;
    userId: string;
    role: string;
    user: {
      id: string;
      name: string | null;
      email: string;
    };
  }[];
}

export default function ProjectsPage() {
  const { data: session } = useSession();
  if (!session?.user?.name || !session?.user?.email) {
    redirect(routes.auth.signIn);
  }

  const { toast } = useToast();
  const selectedTeamId = useTeamId();

  const [projects, setProjects] = useState<Project[]>([]);
  const [showCreateDialog, setShowCreateDialog] = useState(false);
  const [showEditDialog, setShowEditDialog] = useState(false);
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [newProjectName, setNewProjectName] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    if (selectedTeamId && session?.user?.id) {
      void loadProjects();
    }
  }, [selectedTeamId, session?.user?.id]);

  const loadProjects = async () => {
    if (!selectedTeamId || !session?.user?.id || !session?.user?.name || !session?.user?.email)
      return;

    try {
      const fetchedProjects = await fetchTeamProjects(selectedTeamId);
      if (!fetchedProjects || fetchedProjects.length === 0) {
        // If no projects and no db, initialize demo data
        if (!env.NEXT_PUBLIC_FEATURE_DATABASE_ENABLED) {
          LocalTeamStorage.initializeDemoData(
            session.user.id,
            session.user.name,
            session.user.email
          );
          LocalProjectStorage.initializeDemoData(session.user.id, selectedTeamId);
          // Reload projects after seeding demo data
          const demoProjects = await fetchTeamProjects(selectedTeamId);
          setProjects(mapProjects(demoProjects || []));
          return;
        }
      }
      setProjects(mapProjects(fetchedProjects || []));
    } catch (error) {
      console.error("Failed to load projects:", error);
      toast({
        title: "Error",
        description: "Failed to load projects. Please try again.",
        variant: "destructive",
      });
    }
  };

  const mapProjects = (projectsToMap: any[]) => {
    return projectsToMap.map((project) => ({
      ...project,
      teamId: project.teamId ?? selectedTeamId,
      team: project.team ?? { id: selectedTeamId, name: "Default Team" },
    }));
  };

  const handleCreateProject = async () => {
    if (!session?.user?.id || !selectedTeamId) return;

    setIsSubmitting(true);
    try {
      await createProject(newProjectName, selectedTeamId, session.user.id);
      await loadProjects();
      setShowCreateDialog(false);
      setNewProjectName("");
      toast({
        title: "Success",
        description: "Project created successfully.",
      });
    } catch (error) {
      console.error("Failed to create project:", error);
      toast({
        title: "Error",
        description: "Failed to create project. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleUpdateProject = async () => {
    if (!selectedProject) return;

    setIsSubmitting(true);
    try {
      await updateProject(selectedProject.id, newProjectName);
      await loadProjects();
      setShowEditDialog(false);
      setSelectedProject(null);
      setNewProjectName("");
      toast({
        title: "Success",
        description: "Project updated successfully.",
      });
    } catch (error) {
      console.error("Failed to update project:", error);
      toast({
        title: "Error",
        description: "Failed to update project. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeleteProject = async (project: Project) => {
    try {
      await deleteProject(project.id);
      await loadProjects();
      toast({
        title: "Success",
        description: "Project deleted successfully.",
      });
    } catch (error) {
      console.error("Failed to delete project:", error);
      toast({
        title: "Error",
        description: "Failed to delete project. Please try again.",
        variant: "destructive",
      });
    }
  };

  const columns: ColumnDef<Project>[] = [
    {
      accessorKey: "name",
      header: "Name",
    },
    {
      accessorKey: "team.name",
      header: "Team",
    },
    {
      id: "actions",
      cell: ({ row }) => (
        <div className="flex items-center gap-4">
          <button
            type="button"
            onClick={() => {
              setSelectedProject(row.original);
              setNewProjectName(row.original.name);
              setShowEditDialog(true);
            }}
            className="text-sm text-gray-600 hover:text-gray-900"
          >
            Edit
          </button>
          <AlertDialog>
            <AlertDialogTrigger asChild>
              <button type="button" className="text-sm text-red-600 hover:text-red-900">
                Delete
              </button>
            </AlertDialogTrigger>
            <AlertDialogContent>
              <AlertDialogHeader>
                <AlertDialogTitle>Delete Project</AlertDialogTitle>
                <AlertDialogDescription>
                  Are you sure you want to delete this project? This action will also delete all
                  associated API keys and cannot be undone.
                </AlertDialogDescription>
              </AlertDialogHeader>
              <AlertDialogFooter>
                <AlertDialogCancel>Cancel</AlertDialogCancel>
                <AlertDialogAction
                  onClick={() => handleDeleteProject(row.original)}
                  className="bg-red-600 hover:bg-red-700"
                >
                  Delete
                </AlertDialogAction>
              </AlertDialogFooter>
            </AlertDialogContent>
          </AlertDialog>
        </div>
      ),
    },
  ];

  return (
    <div className="container mx-auto py-10">
      <DataTable
        columns={columns}
        data={projects}
        onAdd={() => setShowCreateDialog(true)}
        addButtonLabel="Create Project"
      />

      <DataTableDialog
        open={showCreateDialog}
        onOpenChange={setShowCreateDialog}
        title="Create Project"
        description="Enter the details for your new project."
        onSubmit={handleCreateProject}
        submitLabel="Create"
        isSubmitting={isSubmitting}
        fields={[
          {
            label: "Name",
            value: newProjectName,
            onChange: setNewProjectName,
            placeholder: "Enter project name",
          },
        ]}
      />

      <DataTableDialog
        open={showEditDialog}
        onOpenChange={setShowEditDialog}
        title="Edit Project"
        description="Update your project details."
        onSubmit={handleUpdateProject}
        submitLabel="Update"
        isSubmitting={isSubmitting}
        fields={[
          {
            label: "Name",
            value: newProjectName,
            onChange: setNewProjectName,
            placeholder: "Enter project name",
          },
        ]}
      />
    </div>
  );
}

import type { Metadata } from "next";
import { constructMetadata } from "@/config/metadata";

export const metadata: Metadata = constructMetadata({
  title: "Projects",
  description:
    "Manage your projects and organize your work. Create, edit, and track progress across all your projects.",
});

export default function ProjectsLayout({ children }: { children: React.ReactNode }) {
  return children;
}

"use client";

import type { ColumnDef } from "@tanstack/react-table";
import { useSession } from "next-auth/react";
import { useCallback, useEffect, useState } from "react";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Badge } from "@/components/ui/badge";
import { DataTable } from "@/components/ui/data-table/data-table";
import { DataTableDialog } from "@/components/ui/data-table/data-table-dialog";
import { routes } from "@/config/routes";
import { useToast } from "@/hooks/use-toast";
import { createTeam, deleteTeam, updateTeam } from "@/server/actions/teams";
import type { Team } from "@/types/team";

// Helper to fetch user teams via API
async function fetchUserTeams(): Promise<Team[]> {
  const response = await fetch(routes.api.teams);
  if (!response.ok) {
    return [];
  }
  const data = await response.json();
  return data.teams ?? [];
}

export default function TeamsPage() {
  const { data: session } = useSession();
  const { toast } = useToast();
  const [teams, setTeams] = useState<Team[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [showAddDialog, setShowAddDialog] = useState(false);
  const [showEditDialog, setShowEditDialog] = useState(false);
  const [selectedTeam, setSelectedTeam] = useState<Team | null>(null);
  const [newTeamName, setNewTeamName] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const loadTeams = useCallback(async () => {
    if (!session?.user?.id) return;
    setIsLoading(true);
    try {
      const teams = await fetchUserTeams();
      setTeams(teams);
    } catch (error) {
      console.error("Failed to load teams:", error);
      toast({
        title: "Error",
        description: "Failed to load teams",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  }, [session?.user?.id, toast]);

  useEffect(() => {
    if (session?.user?.id) {
      void loadTeams();
    }
  }, [session?.user?.id, loadTeams]);

  const handleAdd = () => {
    setShowAddDialog(true);
  };

  const handleEdit = (team: Team) => {
    setSelectedTeam(team);
    setNewTeamName(team.team.name);
    setShowEditDialog(true);
  };

  const handleDelete = async (team: Team) => {
    if (team.team.type === "personal") {
      toast({
        title: "Cannot delete personal team",
        description: "Your personal team cannot be deleted.",
        variant: "destructive",
      });
      return;
    }

    try {
      await deleteTeam(team.team.id);
      await loadTeams();

      toast({
        title: "Success",
        description: "Team deleted successfully",
      });
    } catch (error) {
      console.error("Failed to delete team:", error);
      toast({
        title: "Error",
        description: "Failed to delete team",
        variant: "destructive",
      });
    }
  };

  const handleSubmit = async () => {
    if (!session?.user?.id || !newTeamName.trim()) return;
    setIsSubmitting(true);
    try {
      if (selectedTeam) {
        // Update existing team
        await updateTeam(selectedTeam.team.id, { name: newTeamName });

        toast({
          title: "Success",
          description: "Team updated successfully",
        });
      } else {
        // Create new team
        await createTeam(session.user.id, newTeamName);

        toast({
          title: "Success",
          description: "Team created successfully",
        });
      }
      await loadTeams();
      setShowAddDialog(false);
      setShowEditDialog(false);
      setSelectedTeam(null);
      setNewTeamName("");
    } catch (error) {
      console.error("Failed to save team:", error);
      toast({
        title: "Error",
        description: "Failed to save team",
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const columns: ColumnDef<Team>[] = [
    {
      accessorFn: (row) => row.team.name,
      header: "Name",
      cell: ({ row }) => {
        const isPersonal = row.original.team.type === "personal";
        return (
          <div className="flex items-center gap-2">
            {isPersonal && (
              <Badge variant="outline" className="mr-2">
                Personal
              </Badge>
            )}
            {row.original.team.name}
          </div>
        );
      },
    },
    {
      accessorKey: "role",
      header: "Role",
    },
    {
      id: "actions",
      cell: ({ row }) => {
        const isPersonal = row.original.team.type === "personal";
        return (
          <div className="flex items-center gap-4">
            <button
              type="button"
              onClick={() => handleEdit(row.original)}
              className="text-sm text-gray-600 hover:text-gray-900"
            >
              Edit
            </button>
            {!isPersonal && (
              <AlertDialog>
                <AlertDialogTrigger asChild>
                  <button type="button" className="text-sm text-red-600 hover:text-red-900">
                    Delete
                  </button>
                </AlertDialogTrigger>
                <AlertDialogContent>
                  <AlertDialogHeader>
                    <AlertDialogTitle>Delete Team</AlertDialogTitle>
                    <AlertDialogDescription>
                      Are you sure you want to delete this team? This action will also delete all
                      associated projects, API keys, and cannot be undone.
                    </AlertDialogDescription>
                  </AlertDialogHeader>
                  <AlertDialogFooter>
                    <AlertDialogCancel>Cancel</AlertDialogCancel>
                    <AlertDialogAction
                      onClick={(e) => {
                        e.preventDefault();
                        void handleDelete(row.original);
                      }}
                      className="bg-red-600 hover:bg-red-700"
                    >
                      Delete
                    </AlertDialogAction>
                  </AlertDialogFooter>
                </AlertDialogContent>
              </AlertDialog>
            )}
          </div>
        );
      },
    },
  ];

  return (
    <div className="container mx-auto py-10">
      <div className="mb-8">
        <h2 className="text-2xl font-bold tracking-tight">Teams</h2>
        <p className="text-muted-foreground">
          Manage your teams and their members. Every user has a personal team that cannot be
          deleted.
        </p>
      </div>

      <DataTable
        columns={columns}
        data={teams}
        onAdd={handleAdd}
        addButtonLabel="Add Team"
        searchPlaceholder="Filter teams..."
        isLoading={isLoading}
      />

      <DataTableDialog
        open={showAddDialog}
        onOpenChange={setShowAddDialog}
        title="Add Team"
        description="Create a new team to manage projects and collaborate with others."
        onSubmit={() => {
          void handleSubmit();
        }}
        submitLabel="Create"
        isSubmitting={isSubmitting}
        fields={[
          {
            label: "Name",
            value: newTeamName,
            onChange: setNewTeamName,
            placeholder: "Enter team name",
          },
        ]}
      />

      <DataTableDialog
        open={showEditDialog}
        onOpenChange={setShowEditDialog}
        title="Edit Team"
        description={
          selectedTeam?.team.type === "personal"
            ? "Update your personal team's information."
            : "Update your team's information."
        }
        onSubmit={() => {
          void handleSubmit();
        }}
        submitLabel="Save Changes"
        isSubmitting={isSubmitting}
        fields={[
          {
            label: "Name",
            value: newTeamName,
            onChange: setNewTeamName,
            placeholder: "Enter team name",
            type: selectedTeam?.team.type === "personal" ? "disabled" : "text",
          },
        ]}
      />
    </div>
  );
}

import type { Metadata } from "next";
import { constructMetadata } from "@/config/metadata";

export const metadata: Metadata = constructMetadata({
  title: "Teams",
  description:
    "Manage your teams and collaborate with others. Create, edit, and organize teams for your projects.",
});

export default function TeamsLayout({ children }: { children: React.ReactNode }) {
  return children;
}

import { AlertCircleIcon } from "lucide-react";
import type { Metadata } from "next";
import { redirect } from "next/navigation";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { constructMetadata } from "@/config/metadata";
import { routes } from "@/config/routes";
import { createRedirectUrl } from "@/lib/utils/redirect";
import { auth } from "@/server/auth";
import { apiKeyService } from "@/server/services/api-key-service";
import { cacheConfigs, cacheService } from "@/server/services/cache-service";
import { ErrorService } from "@/server/services/error-service";
import { ApiKeysTable } from "./_components/api-keys-table";

export const metadata: Metadata = constructMetadata({
  title: "API Keys",
  description:
    "Manage your API keys for programmatic access. Create, view, and revoke API keys securely.",
});

export default async function ApiKeysPage() {
  const session = await auth({ protect: true });
  if (!session) {
    redirect(createRedirectUrl(routes.auth.signIn, { nextUrl: routes.app.apiKeys }));
  }
  const user = session.user;
  if (!user?.id) {
    redirect(createRedirectUrl(routes.auth.signIn, { nextUrl: routes.app.apiKeys }));
  }

  try {
    // Get user's API keys with caching
    const userApiKeys = await cacheService.getOrSet(
      `user:${user.id}:api-keys`,
      () => apiKeyService.getUserApiKeys(user.id),
      cacheConfigs.short
    );

    // Filter out deleted API keys and map to the format expected by DataTable
    const activeApiKeys = userApiKeys
      ?.filter(({ apiKey }) => !apiKey.deletedAt)
      .map(({ apiKey }) => ({
        ...apiKey,
        createdAt: new Date(apiKey.createdAt),
        lastUsedAt: apiKey.lastUsedAt ? new Date(apiKey.lastUsedAt) : null,
        expiresAt: apiKey.expiresAt ? new Date(apiKey.expiresAt) : null,
      }));

    return (
      <div className="container mx-auto py-10">
        <div className="mb-8">
          <h1 className="text-2xl font-bold tracking-tight">API Keys</h1>
          <p className="text-muted-foreground">
            Manage your API keys for programmatic access. Keep these secure and never share them
            publicly.
          </p>
        </div>

        <ApiKeysTable apiKeys={activeApiKeys ?? []} userId={user.id} />
      </div>
    );
  } catch (error) {
    // Handle errors gracefully
    const appError = ErrorService.handleError(error);
    return (
      <div className="container mx-auto py-10">
        <Alert>
          <AlertCircleIcon className="h-4 w-4" />
          <AlertTitle>Error</AlertTitle>
          <AlertDescription>{appError.message}</AlertDescription>
        </Alert>
      </div>
    );
  }
}

"use client";

import type { ColumnDef } from "@tanstack/react-table";
import { format } from "date-fns";
import { Badge } from "@/components/ui/badge";
import { DataTable } from "@/components/ui/data-table/data-table";
import { createApiKey } from "@/server/actions/api-key-actions";
import { CreateApiKeyDialog } from "./create-api-key-dialog";
import { DeleteApiKeyDialog } from "./delete-api-key-dialog";

// Define the type for our API key data
interface ApiKey {
  id: string;
  key: string;
  name: string;
  description?: string | null;
  createdAt: Date;
  lastUsedAt?: Date | null;
  expiresAt?: Date | null;
  deletedAt?: Date | null;
}

interface ApiKeysTableProps {
  apiKeys: ApiKey[];
  userId: string;
}

// Define the columns for the DataTable
const columns: ColumnDef<ApiKey>[] = [
  {
    accessorKey: "key",
    header: "Key",
    cell: ({ row }) => {
      const key = row.getValue("key") as string;
      return (
        <div className="flex items-center space-x-2">
          <code className="rounded bg-muted px-2 py-1">
            {key.slice(0, 12)}...{key.slice(-4)}
          </code>
        </div>
      );
    },
  },
  {
    accessorKey: "name",
    header: "Name",
    cell: ({ row }) => {
      const description = row.original.description;
      return (
        <div className="space-y-1">
          <div className="font-medium">{row.getValue("name")}</div>
