/**
 * @fileoverview Server actions for API key operations (mutations only)
 * NOTE: For validation, use the service directly:
 * import { apiKeyService } from "@/server/services/api-key-service"
 */

import { revalidatePath } from "next/cache";
import { z } from "zod";
import { routes } from "@/config/routes";
import { auth } from "@/server/auth";
import { apiKeyService } from "@/server/services/api-key-service";
import { ErrorService } from "@/server/services/error-service";
import { ValidationService } from "@/server/services/validation-service";

const MILLISECONDS_IN_A_WEEK = 60 * 60 * 24 * 7 * 1000;

// Validation schemas in a separate object (not exported)
const schemas = {
  createApiKey: z.object({
    userId: z.string(),
    name: z.string().min(1, "Name is required"),
    description: z.string().optional(),
    expiresIn: z.string().optional(),
  }),
} as const;

/**
 * Creates a new API key for a user
 */
export async function createApiKey(data: z.infer<typeof schemas.createApiKey>) {
  try {
    // Validate input
    await ValidationService.validateOrThrow(schemas.createApiKey, data);

    // Ensure user is authenticated and has permission
    const session = await auth();
    if (!session?.user) {
      ErrorService.throwUnauthorized("You must be logged in to create an API key");
    }

    // Ensure user can only create keys for themselves
    if (session.user.id !== data.userId) {
      ErrorService.throwUnauthorized("You can only create API keys for yourself");
    }

    // Convert expiresIn to milliseconds if provided
    const expiresIn = data.expiresIn
      ? Number.parseInt(data.expiresIn) * MILLISECONDS_IN_A_WEEK
      : undefined;

    // Create the API key
    const apiKey = await apiKeyService.createApiKey({
      userId: data.userId,
      name: data.name,
      description: data.description,
      expiresIn,
    });

    // Revalidate the API keys page
    revalidatePath(routes.app.apiKeys);

    // Return the API key - this is the only time it will be shown in full
    return { key: apiKey?.key };
  } catch (error) {
    throw ErrorService.handleError(error);
  }
}

/**
 * Creates a test API key for a user
 */
export async function createTestApiKey() {
  const session = await auth();

  const apiKey = await apiKeyService.createApiKey({
    userId: session?.user?.id ?? "",
    name: "API Key",
    description: "Generated for testing purposes",
  });

  return { key: apiKey?.key };
}

/**
 * Deletes an API key
 */
export async function deleteApiKey(apiKeyId: string) {
  try {
    // Ensure user is authenticated
    const session = await auth();
    if (!session?.user) {
      ErrorService.throwUnauthorized("You must be logged in to delete an API key");
    }

    // Get the API key to check ownership
    const apiKey = await apiKeyService.findById(apiKeyId);
    if (!apiKey) {
      ErrorService.throwNotFound("API key not found");
    }

    // Ensure user can only delete their own keys
    if (apiKey.userId && apiKey.userId !== session.user.id) {
      ErrorService.throwUnauthorized("You can only delete your own API keys");
    }

    // Delete the API key
    const success = await apiKeyService.delete(apiKeyId);

    // Revalidate the API keys page
    revalidatePath(routes.app.apiKeys);

    return success;
  } catch (error) {
    throw ErrorService.handleError(error);
  }
}

"use server";

import { revalidatePath } from "next/cache";
import { routes } from "@/config/routes";
import { validateProjectName } from "@/lib/schemas/deployment";
import { auth } from "@/server/auth";
import type { Deployment } from "@/server/db/schema";
import { type DeploymentResult, deploymentService } from "@/server/services/deployment-service";

/**
 * Server Actions for Deployments
 *
 * These are thin wrappers around the deployment service that handle:
 * - Authentication
 * - Input validation
 * - Cache revalidation
 * - Error formatting for the client
 */

/**
 * Initiates a deployment process by creating a deployment record and
 * then calling the main deployment action.
 */
export async function initiateDeployment(formData: FormData): Promise<DeploymentResult> {
  const session = await auth();
  if (!session?.user?.id) {
    return {
      success: false,
      error: "Authentication required. Please log in to continue.",
    };
  }

  const projectName = formData.get("projectName") as string;

  // Validate project name
  const validation = validateProjectName(projectName);
  if (!validation.isValid) {
    return { success: false, error: validation.error };
  }

  const sanitizedProjectName = projectName.trim();
  const userId = session.user.id;

  // Pre-check repository name availability
  try {
    const availability = await deploymentService.checkRepositoryNameAvailable(
      userId,
      sanitizedProjectName
    );
    if (availability.checked && !availability.available) {
      return {
        success: false,
        error: `A repository named "${sanitizedProjectName}" already exists on your GitHub account. Please choose a different project name.`,
      };
    }
  } catch (preCheckError) {
    console.warn("Pre-check for repository name failed, continuing:", preCheckError);
  }

  try {
    // Create deployment record
    const newDeployment = await deploymentService.createDeployment(userId, {
      projectName: sanitizedProjectName,
      description: `Deployment of ${sanitizedProjectName}`,
      status: "deploying",
    });

    revalidatePath(routes.app.deployments);

    // Trigger deployment in background
    void (async () => {
      try {
        const result = await deploymentService.deployPrivateRepository({
          templateRepo: deploymentService.getDefaultTemplateRepo(),
          projectName: sanitizedProjectName,
          description: `Deployment of ${sanitizedProjectName}`,
          deploymentId: newDeployment.id,
          userId,
        });
        if (!result.success) {
          await deploymentService.updateDeployment(newDeployment.id, userId, {
            status: "failed",
            error: result.error || "Deployment failed",
          });
        }
      } catch (error) {
        console.error(`Deployment failed for ${sanitizedProjectName}:`, error);
        try {
          await deploymentService.updateDeployment(newDeployment.id, userId, {
            status: "failed",
            error: error instanceof Error ? error.message : "An unknown error occurred",
          });
        } catch (updateError) {
          console.error("Failed to update deployment status:", updateError);
        }
      }
    })();

    return {
      success: true,
      message:
        "Deployment started! Monitor progress below - you'll be notified when it completes or if any errors occur.",
      deploymentId: newDeployment.id,
      data: { githubRepo: undefined, vercelProject: undefined },
    };
  } catch (error) {
    console.error(`Failed to create deployment record for ${sanitizedProjectName}:`, error);
    return {
      success: false,
      error: error instanceof Error ? error.message : "Failed to create deployment record",
    };
  }
}

/**
 * Create a new deployment record
 */
export async function createDeployment(
  data: Parameters<typeof deploymentService.createDeployment>[1]
): Promise<Deployment> {
  const session = await auth();
  if (!session?.user?.id) {
    throw new Error("Unauthorized");
  }

  const result = await deploymentService.createDeployment(session.user.id, data);
  revalidatePath(routes.app.deployments);
  return result;
}

/**
 * Update an existing deployment
 */
export async function updateDeployment(
  id: string,
  data: Parameters<typeof deploymentService.updateDeployment>[2],
  userId?: string
): Promise<Deployment | null> {
  // Use provided userId (for background tasks) or get from auth
  let effectiveUserId = userId;

  if (!effectiveUserId) {
    const session = await auth();
    if (!session?.user?.id) {
      throw new Error("Unauthorized");
    }
    effectiveUserId = session.user.id;
  }

  const result = await deploymentService.updateDeployment(id, effectiveUserId, data);

  // Only revalidate when called from a request context (not from background tasks)
  if (result && !userId) {
    revalidatePath(routes.app.deployments);
  }

  return result;
}

/**
 * Delete a deployment record
 */
export async function deleteDeployment(id: string): Promise<boolean> {
  const session = await auth();
  if (!session?.user?.id) {
    throw new Error("Unauthorized");
  }

  const result = await deploymentService.deleteDeployment(id, session.user.id);
  revalidatePath(routes.app.deployments);
  return result;
}

/**
 * Cancel a deployment that is stuck in "deploying" state
 */
export async function cancelDeployment(id: string): Promise<Deployment | null> {
  const session = await auth();
  if (!session?.user?.id) {
    throw new Error("Unauthorized");
  }

  const result = await deploymentService.cancelDeployment(id, session.user.id);
  if (result) {
    revalidatePath(routes.app.deployments);
  }
  return result;
}

"use server";

/**
 * @fileoverview Server actions for private repository deployment (mutations only)
 * NOTE: For read operations like checking availability, use the service directly:
 * import { deploymentService } from "@/server/services/deployment-service"
 */

import { generateProjectNameSuggestions } from "@/lib/utils";
import { auth } from "@/server/auth";
import {
  type DeploymentResult,
  deploymentService,
  type DeploymentConfig as ServiceDeploymentConfig,
} from "@/server/services/deployment-service";

// Re-export from utils for backwards compatibility
export { generateProjectNameSuggestions };

// Types for backwards compatibility
type EnvVarTarget = readonly ("production" | "preview" | "development")[];

export interface DeploymentConfig {
  templateRepo: string;
  projectName: string;
  newRepoName?: string; // Deprecated - use projectName
  description?: string;
  environmentVariables?: {
    key: string;
    value: string;
    target: EnvVarTarget;
  }[];
  domains?: string[];
  includeAllBranches?: boolean;
  githubToken?: string;
  deploymentId?: string;
  userId?: string;
}

/**
 * Deploy a private repository template to user's GitHub and Vercel accounts
 */
export async function deployPrivateRepository(config: DeploymentConfig): Promise<DeploymentResult> {
  // Get userId from config or auth
  let userId = config.userId;

  if (!userId) {
    const session = await auth();
    if (!session?.user?.id) {
      return {
        success: false,
        error: "Authentication required. Please log in to continue.",
      };
    }
    userId = session.user.id;
  }

  // Map old config format to new service format
  const serviceConfig: ServiceDeploymentConfig = {
    templateRepo: config.templateRepo,
    projectName: config.projectName || config.newRepoName || "",
    description: config.description,
    environmentVariables: config.environmentVariables,
    domains: config.domains,
    includeAllBranches: config.includeAllBranches,
    githubToken: config.githubToken,
    deploymentId: config.deploymentId,
    userId,
  };

  return deploymentService.deployPrivateRepository(serviceConfig);
}

