            <ArrowLeftFromLineIcon className="h-4 w-4 shrink-0" />
            <span className="truncate">{siteConfig.title} Home</span>
          </Link>
        </SidebarGroupLabel>
      </SidebarGroup>

      <SidebarGroup className="max-w-full">
        <SidebarGroupLabel className="sr-only">Navigation</SidebarGroupLabel>
        <SidebarMenu className="max-w-full">
          {items.map((item) => renderMenuItem(item))}
        </SidebarMenu>
      </SidebarGroup>
    </>
  );
}

"use client";

import { UserIcon } from "lucide-react";
import { usePathname, useRouter } from "next/navigation";
import { signOut, useSession } from "next-auth/react";
import * as React from "react";
import { UserMenuDropdown } from "@/components/modules/user/user-menu-dropdown";
import { Link } from "@/components/primitives/link";
import { useKeyboardShortcut } from "@/components/providers/keyboard-shortcut-provider";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { BorderBeam } from "@/components/ui/border-beam";
import { Button, buttonVariants } from "@/components/ui/button";
import { type Theme, useThemeToggle } from "@/components/ui/shipkit/theme";
import { ToastAction } from "@/components/ui/toast";
import { ShortcutAction, type ShortcutActionType } from "@/config/keyboard-shortcuts";
import { routes } from "@/config/routes";
import { useSignInRedirectUrl } from "@/hooks/use-auth-redirect";
import { useIsAdmin } from "@/hooks/use-is-admin";
import { useSubscription } from "@/hooks/use-subscription";
import { useToast } from "@/hooks/use-toast";
import { cn } from "@/lib/utils";
import { updateTheme } from "@/server/actions/settings";
import type { User } from "@/types/user";

interface UserMenuProps {
  size?: "default" | "sm";
  className?: string;
  showUpgrade?: boolean;
  user?: User | null;
}

export const UserMenu = ({
  size = "default",
  className,
  showUpgrade = false,
  user,
}: UserMenuProps) => {
  const pathname = usePathname();
  const { data: session, status } = useSession();
  const signInRedirectUrl = useSignInRedirectUrl();
  const { toast } = useToast();
  const [isOpen, setIsOpen] = React.useState(false);
  const { hasActiveSubscription } = useSubscription();
  const router = useRouter();
  const isAdmin = useIsAdmin();

  const currentUser = user ?? session?.user;

  /*
   * Persist theme to the database when the user is logged in.
   * We do this via `useThemeToggle({ onThemeChange })` so ALL theme changes
   * (dropdown + keyboard shortcuts + animated transitions) follow one path.
   */
  const handleThemePersist = React.useCallback(
    async (newTheme: Theme) => {
      if (!currentUser) return;

      try {
        const result = await updateTheme(newTheme);
        if (!result.success) {
          toast({
            title: "Failed to save theme preference",
            description: result.error || "Your theme preference could not be saved.",
            variant: "destructive",
          });
        }

        toast({
          title: "Theme updated",
          description: result.message,
        });
      } catch (error) {
        console.error("Failed to save theme preference:", error);
        toast({
          title: "Failed to save theme preference",
          description: "An unexpected error occurred while saving your theme.",
          variant: "destructive",
        });
      }
    },
    [currentUser, toast]
  );

  const { theme, setLightTheme, setDarkTheme, setSystemTheme } = useThemeToggle({
    onThemeChange: handleThemePersist,
  });

  // Detect invalid session state: user object exists but is missing required fields
  // This can happen after deployment or session invalidation
  const isInvalidSession = React.useMemo(() => {
    if (!currentUser) return false;
    // A valid user must have an id - if currentUser exists but has no id, session is invalid
    if (!currentUser.id) return true;
    // If user has no name AND no image, the session data is likely corrupted/stale
    // This causes the "?" avatar fallback which indicates an invalid session
    if (!currentUser.name && !currentUser.image) return true;
    return false;
  }, [currentUser]);

  // Handle invalid session by logging out and showing a toast
  React.useEffect(() => {
    if (isInvalidSession && status !== "loading") {
      // Sign out without redirect to avoid navigation loop
      void signOut({ redirect: false }).then(() => {
        toast({
          title: "Session expired",
          description: "Your session has expired. Would you like to sign in again?",
          action: (
            <ToastAction altText="Sign in" asChild>
              <Link href={signInRedirectUrl}>Sign in</Link>
            </ToastAction>
          ),
        });
      });
    }
  }, [isInvalidSession, status, toast, signInRedirectUrl]);

  const handleThemeChange = React.useCallback(
    (value: string) => {
      const newTheme = value as Theme;
      switch (newTheme) {
        case "light":
          setLightTheme();
          break;
        case "dark":
          setDarkTheme();
          break;
        case "system":
          setSystemTheme();
          break;
      }
    },
    [setLightTheme, setDarkTheme, setSystemTheme]
  );

  // ---- Refactored Shortcut Handling ----
  const handleShortcut = React.useCallback(
    (event: KeyboardEvent, action: ShortcutActionType) => {
      event.preventDefault();
      switch (action) {
        case ShortcutAction.SET_THEME_LIGHT:
          handleThemeChange("light");
          break;
        case ShortcutAction.SET_THEME_DARK:
          handleThemeChange("dark");
          break;
        case ShortcutAction.SET_THEME_SYSTEM:
          handleThemeChange("system");
          break;
        case ShortcutAction.GOTO_ADMIN:
          if (isAdmin) router.push(routes.admin.index);
          break;
        case ShortcutAction.GOTO_SETTINGS:
          router.push(routes.settings.index);
          break;
        case ShortcutAction.LOGOUT_USER:
          void signOut({ callbackUrl: routes.home });
          break;
      }
    },
    [handleThemeChange, isAdmin, router]
  );

  const isAuthenticated = status === "authenticated";

  useKeyboardShortcut(
    ShortcutAction.SET_THEME_LIGHT,
    (event) => handleShortcut(event, ShortcutAction.SET_THEME_LIGHT),
    undefined,
    [handleShortcut]
  );
  useKeyboardShortcut(
    ShortcutAction.SET_THEME_DARK,
    (event) => handleShortcut(event, ShortcutAction.SET_THEME_DARK),
    undefined,
    [handleShortcut]
  );
  useKeyboardShortcut(
    ShortcutAction.SET_THEME_SYSTEM,
    (event) => handleShortcut(event, ShortcutAction.SET_THEME_SYSTEM),
    undefined,
    [handleShortcut]
  );
  useKeyboardShortcut(
    ShortcutAction.GOTO_ADMIN,
    (event) => handleShortcut(event, ShortcutAction.GOTO_ADMIN),
    () => isAuthenticated && isAdmin,
    [handleShortcut, isAuthenticated, isAdmin]
  );
  useKeyboardShortcut(
    ShortcutAction.GOTO_SETTINGS,
    (event) => handleShortcut(event, ShortcutAction.GOTO_SETTINGS),
    () => isAuthenticated,
    [handleShortcut, isAuthenticated]
  );
  useKeyboardShortcut(
    ShortcutAction.LOGOUT_USER,
    (event) => handleShortcut(event, ShortcutAction.LOGOUT_USER),
    () => isAuthenticated,
    [handleShortcut, isAuthenticated]
  );

  return (
    <div
      className={cn(
        "relative rounded-full flex items-center justify-center aspect-square",
        size === "sm" ? "size-9" : "size-9"
      )}
    >
      {/* Loading state */}
      {status === "loading" && (
        <BorderBeam size={size === "sm" ? 20 : 25} duration={1.5} delay={9} />
      )}

      {/* Not authenticated */}
      {currentUser ? (
        <UserMenuDropdown
          isOpen={isOpen}
          setIsOpen={setIsOpen}
          user={currentUser}
          isAdmin={isAdmin}
          showUpgrade={showUpgrade}
          hasActiveSubscription={hasActiveSubscription}
          theme={theme}
          handleThemeChange={handleThemeChange}
        >
          <Button
            variant="ghost"
            size="icon"
            className={cn("relative rounded-full", size === "sm" ? "size-6" : "size-8", className)}
            aria-label="User menu"
          >
            <Avatar className={cn(size === "sm" ? "size-6" : "size-8")}>
              <AvatarImage
                src={currentUser?.image || ""}
                alt={currentUser?.name || "User avatar"}
                draggable={false}
              />
              <AvatarFallback>{currentUser?.name?.[0]?.toUpperCase() || "?"}</AvatarFallback>
            </Avatar>
          </Button>
        </UserMenuDropdown>
      ) : (
        <>
          {pathname !== routes.auth.signIn && pathname !== routes.auth.signUp ? (
            <Link
              href={signInRedirectUrl}
              className={cn(
                buttonVariants({ variant: "ghost", size: "icon" }),
                "rounded-full cursor-pointer"
              )}
            >
              <UserIcon className="size-6" />
            </Link>
          ) : (
            <Button variant="ghost" size="icon" className={cn("relative rounded-full", className)}>
              <UserIcon className="size-6" />
            </Button>
          )}
        </>
      )}
    </div>
  );
};

"use client";

import {
  DesktopIcon,
  ExitIcon,
  GearIcon,
  LockClosedIcon,
  MoonIcon,
  PersonIcon,
  RocketIcon,
  SunIcon,
} from "@radix-ui/react-icons";
import { Sparkles } from "lucide-react";
import Link from "next/link";
import { signOut } from "next-auth/react";
import type * as React from "react";
import { RestartOnboardingButton } from "@/components/modules/onboarding/onboarding-check";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuGroup,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuRadioGroup,
  DropdownMenuRadioItem,
  DropdownMenuSeparator,
  DropdownMenuShortcut,
  DropdownMenuSub,
  DropdownMenuSubContent,
  DropdownMenuSubTrigger,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { routes } from "@/config/routes";
import { cn } from "@/lib/utils";
import type { User } from "@/types/user";
export interface MenuItemProps {
  href?: string;
  onClick?: () => void;
  label: string;
  icon?: React.ReactNode;
  shortcut?: string;
  className?: string;
}

interface UserMenuDropdownProps {
  isOpen: boolean;
  setIsOpen: React.Dispatch<React.SetStateAction<boolean>>;
  user?: User;
  isAdmin?: boolean;
  showUpgrade?: boolean;
  hasActiveSubscription?: boolean;
  showOnboarding?: boolean;
  theme?: string;
  handleThemeChange?: (value: string) => void;
  children: React.ReactNode;
  align?: "start" | "center" | "end";
  side?: "top" | "right" | "bottom" | "left";
  sideOffset?: number;
  className?: string;
  contentClassName?: string;
  additionalMenuItems?: MenuItemProps[];
}

export function UserMenuDropdown({
  isOpen,
  setIsOpen,
  user,
  isAdmin = false,
  showUpgrade = false,
  hasActiveSubscription = false,
  showOnboarding = false,
  theme,
  handleThemeChange,
  children,
  align = "end",
  side,
  sideOffset = 4,
  className,
  contentClassName,
  additionalMenuItems = [],
}: UserMenuDropdownProps) {
  const handleSignOut = () => {
    setIsOpen(false);
    signOut();
  };

  return (
    <DropdownMenu open={isOpen} onOpenChange={setIsOpen}>
      <DropdownMenuTrigger asChild className={className}>
        {children}
      </DropdownMenuTrigger>
      <DropdownMenuContent
        className={cn("w-56", contentClassName)}
        align={align}
        side={side}
        sideOffset={sideOffset}
        forceMount
        onCloseAutoFocus={(event) => {
          event.preventDefault();
        }}
      >
        <DropdownMenuLabel className="font-normal">
          <div className="flex flex-col space-y-1">
            <p className="text-sm font-medium leading-none">{user?.name ?? "Guest User"}</p>
            <p className="text-xs leading-none text-muted-foreground">
              {user?.email || "Not signed in"}
            </p>
          </div>
        </DropdownMenuLabel>
        <DropdownMenuSeparator />

        {showUpgrade && !hasActiveSubscription && (
          <>
            <DropdownMenuGroup>
              <DropdownMenuItem asChild>
                <Link href={routes.pricing}>
                  <Sparkles className="mr-2 size-4" />
                  Upgrade to Pro
                </Link>
              </DropdownMenuItem>
            </DropdownMenuGroup>
            <DropdownMenuSeparator />
          </>
        )}

        <DropdownMenuGroup>
          {isAdmin && (
            <DropdownMenuItem asChild>
              <Link href={routes.admin.index}>
                <PersonIcon className="mr-2 size-4" />
                Admin
                <DropdownMenuShortcut>⌘A</DropdownMenuShortcut>
              </Link>
            </DropdownMenuItem>
          )}
          <DropdownMenuItem asChild>
            <Link href={routes.app.dashboard}>
              <RocketIcon className="mr-2 size-4" />
              Dashboard
              <DropdownMenuShortcut>⌘D</DropdownMenuShortcut>
            </Link>
          </DropdownMenuItem>
          <DropdownMenuItem asChild>
            <Link href={routes.settings.index}>
              <GearIcon className="mr-2 size-4" />
              Settings
              <DropdownMenuShortcut>⌘S</DropdownMenuShortcut>
            </Link>
          </DropdownMenuItem>
          {showOnboarding && (
            <DropdownMenuItem asChild>
              <RestartOnboardingButton
                user={user}
                className="w-full justify-start"
                forceVisible={isAdmin}
              />
            </DropdownMenuItem>
          )}

          {additionalMenuItems.map((item) => (
            <DropdownMenuItem
              key={`menu-item-${item.label}`}
              asChild={!!item.href}
              onClick={item.onClick}
              className={item.className}
            >
              {item.href ? (
                <Link href={item.href}>
                  {item.icon && <span className="mr-2">{item.icon}</span>}
                  {item.label}
                  {item.shortcut && <DropdownMenuShortcut>{item.shortcut}</DropdownMenuShortcut>}
                </Link>
              ) : (
                <>
                  {item.icon && <span className="mr-2">{item.icon}</span>}
                  {item.label}
                  {item.shortcut && <DropdownMenuShortcut>{item.shortcut}</DropdownMenuShortcut>}
                </>
              )}
            </DropdownMenuItem>
          ))}
        </DropdownMenuGroup>

        {handleThemeChange && (
          <>
            <DropdownMenuSeparator />
            <DropdownMenuSub>
              <DropdownMenuSubTrigger>
                <SunIcon className="mr-2 size-4" />
                <span>Theme</span>
              </DropdownMenuSubTrigger>
              <DropdownMenuSubContent>
                <DropdownMenuRadioGroup value={theme || "system"} onValueChange={handleThemeChange}>
                  <DropdownMenuRadioItem value="light" className="flex items-center gap-2">
                    <SunIcon className="size-4" />
                    <span>Light</span>
                    <DropdownMenuShortcut>⌘L</DropdownMenuShortcut>
                  </DropdownMenuRadioItem>
                  <DropdownMenuRadioItem value="dark" className="flex items-center gap-2">
                    <MoonIcon className="size-4" />
                    <span>Dark</span>
                    <DropdownMenuShortcut>⇧⌘D</DropdownMenuShortcut>
                  </DropdownMenuRadioItem>
                  <DropdownMenuRadioItem value="system" className="flex items-center gap-2">
                    <DesktopIcon className="size-4" />
                    <span>System</span>
                    <DropdownMenuShortcut>⌘B</DropdownMenuShortcut>
                  </DropdownMenuRadioItem>
                </DropdownMenuRadioGroup>
              </DropdownMenuSubContent>
            </DropdownMenuSub>
          </>
        )}

        <DropdownMenuSeparator />
        <DropdownMenuItem className="text-red-600 dark:text-red-400" onClick={handleSignOut}>
          <ExitIcon className="mr-2 size-4" />
          Sign out
          <DropdownMenuShortcut>⇧⌘Q</DropdownMenuShortcut>
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

"use client";

import { ResetIcon } from "@radix-ui/react-icons";
import { useEffect, useState } from "react";
import { OnboardingWizard } from "@/components/modules/onboarding/onboarding-wizard";
import { Button } from "@/components/ui/button";
import { env } from "@/env";
import { useLocalStorage } from "@/hooks/use-local-storage";
import type { User } from "@/types/user";

interface OnboardingCheckProps {
  user?: User | null;
  hasGitHubConnection?: boolean;
  hasVercelConnection?: boolean;
  hasPurchased?: boolean;
  githubUsername?: string | null;
  /**
   * Force enable the onboarding wizard even if feature flags are disabled.
   * Useful for administrators or internal testing.
   */
  forceEnabled?: boolean;
}

export function OnboardingCheck({
  user,
  hasGitHubConnection = false,
  hasVercelConnection = false,
  hasPurchased = false,
  githubUsername,
  forceEnabled = false,
}: OnboardingCheckProps) {
  const userId = user?.id ?? "";
  const [showOnboarding, setShowOnboarding] = useState(false);
  const [onboardingState, _setOnboardingState] = useLocalStorage<{
    completed: boolean;
    currentStep: number;
    steps: Record<string, boolean>;
  } | null>(`onboarding-${userId}`, null);

  useEffect(() => {
    // Only show onboarding if:
    // 1. User has purchased the starter kit (or is admin via forceEnabled)
    // 2. Onboarding hasn't been completed yet
    // 3. We have a valid userId
    if ((hasPurchased || forceEnabled) && userId && !onboardingState?.completed) {
      setShowOnboarding(true);
    } else {
      setShowOnboarding(false);
    }
  }, [hasPurchased, forceEnabled, userId, onboardingState]);

  // Onboarding requires both Vercel and GitHub integrations to be configured.
  // Without both, the wizard steps can't function — hide it regardless of admin status.
  if (
    !env.NEXT_PUBLIC_FEATURE_VERCEL_INTEGRATION_ENABLED ||
    !env.NEXT_PUBLIC_FEATURE_GITHUB_API_ENABLED ||
    !env.NEXT_PUBLIC_FEATURE_DATABASE_ENABLED
  ) {
    return null;
  }

  if (!showOnboarding || !user) {
    return null;
  }

  const handleOnboardingComplete = () => {
    setShowOnboarding(false);
  };

  return (
    <OnboardingWizard
      user={user}
      hasGitHubConnection={hasGitHubConnection}
      hasVercelConnection={hasVercelConnection}
      githubUsername={githubUsername}
      onComplete={handleOnboardingComplete}
    />
  );
}

// Separate component for the restart button
export function RestartOnboardingButton({
  user,
  hasGitHubConnection = false,
  hasVercelConnection = false,
  className = "",
  /**
   * When true, always render the button (e.g., for admins), even if onboarding was not completed.
   */
  forceVisible = false,
}: OnboardingCheckProps & { className?: string; forceVisible?: boolean }) {
  const [onboardingState, setOnboardingState] = useLocalStorage<{
    completed: boolean;
    currentStep: number;
    steps: Record<string, boolean>;
  } | null>(`onboarding-${user?.id}`, null);

  const restartOnboarding = () => {
    // Ensure IntroDisclosure (feature tour) is reset as well
    // Matches key used in `IntroDisclosure` via useFeatureVisibility: `feature_${featureId}`
    // We pass `featureId` as `onboarding-${user?.id}` in the wizard, so full key becomes `feature_onboarding-${user?.id}`
    if (user?.id) {
      try {
        localStorage.removeItem(`feature_onboarding-${user.id}`);
      } catch (e) {
        console.error("Failed to remove onboarding state from localStorage:", e);
      }
    }

    // Reset the onboarding state to initial values
    setOnboardingState({
      completed: false,
      currentStep: 0,
      steps: {
        github: hasGitHubConnection, // Keep GitHub connection status
        vercel: hasVercelConnection, // Keep Vercel connection status
        deploy: false,
      },
    });
    window?.location?.reload();
  };

  // Hide the button unless all required integrations are enabled (regardless of forceVisible).
  if (
    !env.NEXT_PUBLIC_FEATURE_VERCEL_INTEGRATION_ENABLED ||
    !env.NEXT_PUBLIC_FEATURE_GITHUB_API_ENABLED ||
    !env.NEXT_PUBLIC_FEATURE_DATABASE_ENABLED
  ) {
    return null;
  }

  // Only show the button if onboarding has been completed before,
  // unless forceVisible is enabled (e.g., for admins to start onboarding).
  if (!forceVisible && !onboardingState?.completed) {
    return null;
  }

  return (
    <Button type="button" variant="ghost" onClick={restartOnboarding} className={className}>
      <ResetIcon className="mr-2 size-4" />
      {onboardingState?.completed ? "Restart Onboarding" : "Start Onboarding"}
    </Button>
  );
}

"use client";

import {
  LifeBuoy,
  type LucideIcon,
  PanelLeftClose,
  PanelLeftOpen,
  Send,
  Settings2,
} from "lucide-react";
import type React from "react";
import { FeedbackDialog } from "@/components/forms/feedback-dialog";
import { Link } from "@/components/primitives/link";
import { Button, buttonVariants } from "@/components/ui/button";
import { useSidebar } from "@/components/ui/sidebar";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import { routes } from "@/config/routes";
import { cn } from "@/lib/utils";

const data = [
  {
    title: "Feedback",
    Icon: Send,
    href: "#feedback",
    component: FeedbackDialog,
  },
  {
    title: "Documentation",
    Icon: LifeBuoy,
    href: routes.docs,
  },
  {
    title: "Settings",
    Icon: Settings2,
    href: routes.settings.index,
  },
];

interface NavSecondaryItem {
  title: string;
  href: string;
  Icon: LucideIcon;
  component?: React.ComponentType<{ trigger?: React.ReactNode }>;
}

interface NavSecondaryProps {
  items?: NavSecondaryItem[];
  className?: string;
}

// Extract common button and tooltip wrapper into a component
interface NavItemWrapperProps {
  title: string;
  open: boolean;
  children: React.ReactNode;
}

const NavItemWrapper = ({ title, open, children }: NavItemWrapperProps) => {
  if (open) {
    return children;
  }

  return (
    <Tooltip>
      <TooltipTrigger asChild>{children}</TooltipTrigger>
      <TooltipContent side="right" sideOffset={20}>
        {title}
      </TooltipContent>
    </Tooltip>
  );
};

// Extract common button props
const getButtonProps = (open: boolean) => ({
  variant: "ghost" as const,
  size: "sm" as const,
  className: cn("group justify-center", open && "w-full justify-start"),
});

export function NavSecondary({ items, className }: NavSecondaryProps) {
  const { open, state, toggleSidebar } = useSidebar();
  if (!items) items = data;

  return (
    <nav className={cn("flex flex-col gap-1", className)}>
      {items.map((item) => {
        const Icon = item.Icon;
        const buttonProps = getButtonProps(open);

        // If there's a custom component (like FeedbackDialog), use it
        if (item.component) {
          const Component = item.component;
          return (
            <Component
              key={item.title}
              trigger={
                <NavItemWrapper title={item.title} open={open}>
                  <Button
                    {...buttonProps}
                    className="w-full justify-start group-data-[collapsible=icon]:px-2"
                  >
                    <Icon className="h-4 w-4 shrink-0" />
                    {open && (
                      <span className="ml-2 transition-all duration-200 group-data-[collapsible=icon]:opacity-0">
                        {item.title}
                      </span>
                    )}
                  </Button>
                </NavItemWrapper>
              }
            />
          );
        }

        // Regular link — use Link with buttonVariants styling directly
        // to avoid Slot composition issues with next-view-transitions
        return (
          <NavItemWrapper key={item.title} title={item.title} open={open}>
            <Link
              href={item?.href ?? "#"}
              className={cn(
                buttonVariants({ variant: "ghost", size: "sm" }),
                "group justify-center",
                open && "w-full justify-start"
              )}
            >
              <Icon className="h-4 w-4 shrink-0" />
              {open && (
                <span className="ml-2 transition-all duration-200 group-data-[collapsible=icon]:opacity-0">
                  {item.title}
                </span>
              )}
            </Link>
          </NavItemWrapper>
        );
      })}

      <NavItemWrapper
        title={state === "collapsed" ? "Expand sidebar" : "Collapse sidebar"}
        open={open}
      >
        <Button
          {...getButtonProps(open)}
          type="button"
          onClick={toggleSidebar}
          aria-label={state === "collapsed" ? "Expand sidebar" : "Collapse sidebar"}
        >
          {state === "collapsed" ? (
            <PanelLeftOpen className="h-4 w-4 shrink-0" />
          ) : (
            <PanelLeftClose className="h-4 w-4 shrink-0" />
          )}
          {open && (
            <span className="ml-2 transition-all duration-200 group-data-[collapsible=icon]:opacity-0">
              {state === "collapsed" ? "Expand sidebar" : "Collapse sidebar"}
            </span>
          )}
        </Button>
      </NavItemWrapper>
    </nav>
  );
}
